16	  font-family: 'JetBrainsMono NF', 'JetBrainsMonoNL NF', 'JetBrains Mono', 'Cascadia Code', 'Consolas', monospace;
17	}
18	
19	/* --- Galaxy background (v0) --- */
20	.galaxy-layer::after {
21	  content: '';
22	  position: absolute;
23	  inset: 0;
24	  background: rgba(6, 6, 15, 0.15);
25	}
