27	.nebula-overlay {
28	  background:
29	    radial-gradient(ellipse at 30% 20%, rgba(100, 150, 255, 0.1) 0%, transparent 50%),
30	    radial-gradient(ellipse at 70% 80%, rgba(200, 100, 255, 0.08) 0%, transparent 50%);
31	}
32	
33	.cosmic-border-glow {
34	  box-shadow: inset 0 0 0 1px rgba(110, 181, 217, 0.12);
35	}
