52	/* --- Glass panels for text readability --- */
53	.terminal-mask {
54	  background: rgba(6, 6, 15, 0.3);
55	  backdrop-filter: blur(6px);
56	}
57	
58	/* --- Scrollbar styling --- */
59	::-webkit-scrollbar {
60	  width: 6px;
61	}
62	::-webkit-scrollbar-track {
63	  background: transparent;
64	}
65	::-webkit-scrollbar-thumb {
66	  background: #1e1e3a;
67	  border-radius: 3px;
68	}
69	::-webkit-scrollbar-thumb:hover {
70	  background: #2e2e5a;
71	}
72	
73	/* ==============================
74	   Splash Screen  v2 — deep-space upgrade
75	   ============================== */
76	
77	/* ---------- overlay ---------- */
78	.splash-overlay {
79	  position: fixed;
80	  inset: 0;
81	  z-index: 100;
82	  display: flex;
83	  flex-direction: column;
84	  align-items: center;
85	  justify-content: center;
86	  background: radial-gradient(ellipse 80% 60% at 50% 45%, #0f0b2e 0%, #070615 55%, #02020a 100%);
87	  animation: splash-exit 1s ease-in 3s forwards;
88	  overflow: hidden;
89	}
90	
91	/* ---------- nebula depth layers ---------- */
92	.nebula {
93	  position: fixed;
94	  border-radius: 50%;
95	  filter: blur(90px);
96	  pointer-events: none;
97	  will-change: transform, opacity;
98	}
99	.nebula-a {
100	  width: 55vw; height: 55vh;
101	  left: -12vw; top: 8vh;
102	  background: radial-gradient(ellipse at center, rgba(124, 111, 247, 0.09) 0%, transparent 70%);
103	  animation: nebula-drift 11s ease-in-out infinite;
104	}
105	.nebula-b {
106	  width: 48vw; height: 48vh;
107	  right: -10vw; bottom: 2vh;
108	  background: radial-gradient(ellipse at center, rgba(110, 181, 217, 0.07) 0%, transparent 70%);
109	  animation: nebula-drift 13s ease-in-out infinite reverse;
110	}
111	.nebula-c {
112	  width: 40vw; height: 40vh;
113	  left: 30vw; top: 50vh;
114	  background: radial-gradient(ellipse at center, rgba(201, 143, 212, 0.06) 0%, transparent 70%);
115	  animation: nebula-drift 15s ease-in-out infinite;
116	}
117	
118	/* ---------- starfield ---------- */
119	.splash-star {
120	  position: fixed;
121	  border-radius: 50%;
122	  background: #e8e4ff;
123	  animation: star-twinkle ease-in-out infinite;
124	  pointer-events: none;
125	  will-change: opacity, transform;
126	}
127	@keyframes star-twinkle {
128	  0%, 100% { opacity: 0.08; transform: translate3d(0, 0, 0) scale(0.6); }
129	  40%      { opacity: 0.4;  transform: translate3d(0, 0, 0) scale(1); }
130	  70%      { opacity: 0.9;  transform: translate3d(0, 0, 0) scale(1.5); }
131	}
132	
133	/* ---------- galaxy centrepiece ---------- */
