168	  left: 50%;
169	  width: 5px; height: 5px;
170	  margin-left: -2.5px;
171	  border-radius: 50%;
172	  background: #c4b5fd;
173	  box-shadow: 0 0 8px 2px rgba(167, 139, 250, 0.7), 0 0 18px 4px rgba(124, 111, 247, 0.3);
174	}
175	
176	@keyframes orbit-spin {
177	  0%   { transform: translate3d(0, 0, 0) rotate(0deg); }
178	  100% { transform: translate3d(0, 0, 0) rotate(360deg); }
179	}
180	
181	/* ----- spiral arms ----- */
182	.galaxy-arm {
