193	             arm-spin 10s 1.7s linear infinite;
194	}
195	.arm-2 {
196	  border-top-color: rgba(167, 139, 250, 0.4);
197	  border-left-color: rgba(124, 111, 247, 0.22);
198	  animation: arm-unfurl 1.4s 0.35s cubic-bezier(0.16, 1, 0.3, 1) forwards,
199	             arm-spin 13s 1.75s linear infinite reverse;
200	}
201	.arm-3 {
202	  border-bottom-color: rgba(124, 111, 247, 0.35);
203	  border-right-color: rgba(196, 181, 253, 0.2);
204	  animation: arm-unfurl 1.3s 0.5s cubic-bezier(0.16, 1, 0.3, 1) forwards,
205	             arm-spin 17s 1.8s linear infinite;
206	}
207	.arm-4 {
208	  border-top-color: rgba(167, 139, 250, 0.28);
