file.content:
@tailwind base;
@tailwind components;
@tailwind utilities;

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html, body, #root {
  height: 100%;
  width: 100%;
  overflow: hidden;
  background: #0a0a14;
  font-family: 'JetBrainsMono NF', 'JetBrainsMonoNL NF', 'JetBrains Mono', 'Cascadia Code', 'Consolas', monospace;
}

/* --- Galaxy background (v0) --- */
.galaxy-layer::after {
  content: '';
  position: absolute;
  inset: 0;
  background: rgba(6, 6, 15, 0.15);
}

.nebula-overlay {
  background:
    radial-gradient(ellipse at 30% 20%, rgba(100, 150, 255, 0.1) 0%, transparent 50%),
    radial-gradient(ellipse at 70% 80%, rgba(200, 100, 255, 0.08) 0%, transparent 50%);
}

.cosmic-border-glow {
  box-shadow: inset 0 0 0 1px rgba(110, 181, 217, 0.12);
}

.glass-panel {
  background: rgba(18, 18, 31, 0.35);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}

.terminal-chrome {
  background: rgba(18, 18, 31, 0.5);
  backdrop-filter: blur(8px);
}

.terminal-text-glow {
  text-shadow: 0 0 5px currentColor;
}

/* --- Glass panels for text readability --- */
.terminal-mask {
  background: rgba(6, 6, 15, 0.3);
  backdrop-filter: blur(6px);
}

/* --- Scrollbar styling --- */
::-webkit-scrollbar {
  width: 6px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: #1e1e3a;
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover {
  background: #2e2e5a;
}

/* ==============================
   Splash Screen  v2 — deep-space upgrade
   ============================== */

/* ---------- overlay ---------- */
.splash-overlay {
  position: fixed;
  inset: 0;
  z-index: 100;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  background: radial-gradient(ellipse 80% 60% at 50% 45%, #0f0b2e 0%, #070615 55%, #02020a 100%);
  animation: splash-exit 1s ease-in 3s forwards;
  overflow: hidden;
}

/* ---------- nebula depth layers ---------- */
.nebula {
  position: fixed;
  border-radius: 50%;
  filter: blur(90px);
  pointer-events: none;
  will-change: transform, opacity;
}
.nebula-a {
  width: 55vw; height: 55vh;
  left: -12vw; top: 8vh;
  background: radial-gradient(ellipse at center, rgba(124, 111, 247, 0.09) 0%, transparent 70%);
  animation: nebula-drift 11s ease-in-out infinite;
}
.nebula-b {
  width: 48vw; height: 48vh;
  right: -10vw; bottom: 2vh;
  background: radial-gradient(ellipse at center, rgba(110, 181, 217, 0.07) 0%, transparent 70%);
  animation: nebula-drift 13s ease-in-out infinite reverse;
}
.nebula-c {
  width: 40vw; height: 40vh;
  left: 30vw; top: 50vh;
  background: radial-gradient(ellipse at center, rgba(201, 143, 212, 0.06) 0%, transparent 70%);
  animation: nebula-drift 15s ease-in-out infinite;
}

/* ---------- starfield ---------- */
.splash-star {
  position: fixed;
  border-radius: 50%;
  background: #e8e4ff;
  animation: star-twinkle ease-in-out infinite;
  pointer-events: none;
  will-change: opacity, transform;
}
@keyframes star-twinkle {
  0%, 100% { opacity: 0.08; transform: translate3d(0, 0, 0) scale(0.6); }
  40%      { opacity: 0.4;  transform: translate3d(0, 0, 0) scale(1); }
  70%      { opacity: 0.9;  transform: translate3d(0, 0, 0) scale(1.5); }
}

/* ---------- galaxy centrepiece ---------- */
.galaxy-container {
  position: relative;
  width: 280px;
  height: 280px;
  margin-bottom: 52px;
}

/* ----- orbital particle rings ----- */
.orbit-ring {
  position: absolute;
  border-radius: 50%;
  pointer-events: none;
  will-change: transform;
  border: 1px solid rgba(124, 111, 247, 0.22);
}
.ring-r1 {
  inset: 20%;
  border-color: rgba(167, 139, 250, 0.42);
  animation: orbit-spin 7s linear infinite;
}
.ring-r2 {
  inset: 10%;
  border-color: rgba(124, 111, 247, 0.3);
  animation: orbit-spin 11s linear infinite reverse;
}
.ring-r3 {
  inset: 0;
  border-color: rgba(196, 181, 253, 0.24);
  animation: orbit-spin 16s linear infinite;
}

.orbit-dot {
  position: absolute;
  top: -2px;
  left: 50%;
  width: 5px; height: 5px;
  margin-left: -2.5px;
  border-radius: 50%;
  background: #c4b5fd;
  box-shadow: 0 0 8px 2px rgba(167, 139, 250, 0.7), 0 0 18px 4px rgba(124, 111, 247, 0.3);
}

@keyframes orbit-spin {
  0%   { transform: translate3d(0, 0, 0) rotate(0deg); }
  100% { transform: translate3d(0, 0, 0) rotate(360deg); }
}

/* ----- spiral arms ----- */
.galaxy-arm {
  position: absolute;
  inset: 0;
  border-radius: 50%;
  border: 1.5px solid transparent;
  opacity: 0;
}
.arm-1 {
  border-top-color: rgba(124, 111, 247, 0.45);
  border-right-color: rgba(167, 139, 250, 0.2);
  animation: arm-unfurl 1.5s 0.2s cubic-bezier(0.16, 1, 0.3, 1) forwards,
             arm-spin 10s 1.7s linear infinite;
}
.arm-2 {
  border-top-color: rgba(167, 139, 250, 0.4);
  border-left-color: rgba(124, 111, 247, 0.22);
  animation: arm-unfurl 1.4s 0.35s cubic-bezier(0.16, 1, 0.3, 1) forwards,
             arm-spin 13s 1.75s linear infinite reverse;
}
.arm-3 {
  border-bottom-color: rgba(124, 111, 247, 0.35);
  border-right-color: rgba(196, 181, 253, 0.2);
  animation: arm-unfurl 1.3s 0.5s cubic-bezier(0.16, 1, 0.3, 1) forwards,
             arm-spin 17s 1.8s linear infinite;
}
.arm-4 {
  border-top-color: rgba(167, 139, 250, 0.28);
  border-left-color: rgba(218, 119, 242, 0.18);
  animation: arm-unfurl 1.2s 0.65s cubic-bezier(0.16, 1, 0.3, 1) forwards,
             arm-spin 21s 1.85s linear infinite reverse;
}

@keyframes arm-unfurl {
  0%   { opacity: 0; transform: translate3d(0, 0, 0) scale(0.12); }
  100% { opacity: 1; transform: translate3d(0, 0, 0) scale(1); }
}
@keyframes arm-spin {
  0%   { transform: translate3d(0, 0, 0) rotate(0deg); }
  100% { transform: translate3d(0, 0, 0) rotate(360deg); }
}

/* ----- core (3-layer for depth) ----- */
.galaxy-core {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  animation: core-emerge 0.8s 0.6s cubic-bezier(0.16, 1, 0.3, 1) forwards;
  opacity: 0;
  transform: translate3d(0, 0, 0) scale(0);
}

/* Outer — soft wide aura */
.galaxy-core::before {
  content: '';
  position: absolute;
  width: 70px; height: 70px;
  border-radius: 50%;
  animation: core-aura 3s 1.4s ease-in-out infinite;
  will-change: box-shadow;
}

/* Inner glow orb */
.core-mid {
  width: 32px; height: 32px;
  border-radius: 50%;
  background: radial-gradient(circle at 35% 35%, #ddd6fe, #8b7cf7 55%, #5b4fcf);
  box-shadow:
    0 0 20px 3px rgba(139, 124, 247, 0.6),
    0 0 50px 10px rgba(124, 111, 247, 0.25);
  animation: core-breathe 2.8s 1.4s ease-in-out infinite;
}

/* Hot centre pin-prick */
.core-hot {
  position: absolute;
  width: 8px; height: 8px;
  border-radius: 50%;
  background: #f5f0ff;
  box-shadow: 0 0 12px 3px rgba(167, 139, 250, 0.85);
}

@keyframes core-emerge {
  0%   { opacity: 0; transform: translate3d(0, 0, 0) scale(0); }
  60%  { opacity: 1; transform: translate3d(0, 0, 0) scale(1.18); }
  100% { opacity: 1; transform: translate3d(0, 0, 0) scale(1); }
}

@keyframes core-breathe {
  0%, 100% {
    box-shadow:
      0 0 22px 4px rgba(139, 124, 247, 0.55),
      0 0 55px 12px rgba(124, 111, 247, 0.22);
  }
  50% {
    box-shadow:
      0 0 36px 8px rgba(167, 139, 250, 0.75),
      0 0 80px 22px rgba(124, 111, 247, 0.32);
  }
}

@keyframes core-aura {
  0%, 100% {
    box-shadow:
      0 0 40px 8px rgba(124, 111, 247, 0.18),
      0 0 100px 24px rgba(110, 181, 217, 0.06);
  }
  50% {
    box-shadow:
      0 0 60px 14px rgba(167, 139, 250, 0.28),
      0 0 140px 36px rgba(124, 111, 247, 0.1);
  }
}

/* ---------- title block ---------- */
.splash-title-wrap {
  text-align: center;
  animation: title-emerge 1s 1s cubic-bezier(0.16, 1, 0.3, 1) forwards;
  opacity: 0;
  transform: translate3d(0, 24px, 0);
}

.splash-title {
  font-family: 'JetBrains Mono', 'Cascadia Code', 'Consolas', monospace;
  font-size: 2.25rem;
  font-weight: 800;
  letter-spacing: 0.38em;
  background: linear-gradient(135deg, #7c6ff7 0%, #c4b5fd 18%, #a78bfa 50%, #da77f2 78%, #7c6ff7 100%);
  background-size: 220% 220%;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  animation: title-shimmer 3.5s ease-in-out infinite;
  margin-bottom: 14px;
  user-select: none;
}

.splash-sub {
  font-family: 'JetBrains Mono', 'Cascadia Code', 'Consolas', monospace;
  font-size: 0.68rem;
  font-weight: 400;
  letter-spacing: 0.5em;
  color: rgba(167, 139, 250, 0.65);
  user-select: none;
  min-height: 1.2em;  /* prevent layout jump while typing */
}

.splash-cursor {
  display: inline-block;
  color: rgba(196, 181, 253, 0.85);
  font-weight: 300;
  animation: cursor-flash 0.55s step-end infinite;
}

@keyframes cursor-flash {
  0%, 100% { opacity: 1; }
  50%      { opacity: 0; }
}

/* ---------- shared keyframes ---------- */

@keyframes nebula-drift {
  0%, 100% { transform: translate3d(0, 0, 0) scale(1); }
  33%      { transform: translate3d(12px, -10px, 0) scale(1.08); }
  66%      { transform: translate3d(-8px, 14px, 0) scale(0.94); }
}

@keyframes title-emerge {
  0%   { opacity: 0; transform: translate3d(0, 24px, 0); filter: blur(8px); }
  100% { opacity: 1; transform: translate3d(0, 0, 0);    filter: blur(0); }
}

@keyframes title-shimmer {
  0%, 100% { background-position: 0% 50%; }
  50%      { background-position: 100% 50%; }
}

@keyframes splash-exit {
  0%   { opacity: 1; transform: translate3d(0, 0, 0) scale(1); }
  100% { opacity: 0; transform: translate3d(0, 0, 0) scale(1.05); pointer-events: none; }
}

/* ==============================
   Search Bar  — frosted glass slide-in
   ============================== */

.search-bar {
  animation: search-slide-in 0.22s cubic-bezier(0.16, 1, 0.3, 1);
}

.search-bar-inner {
  display: flex;
  align-items: center;
  gap: 6px;
  margin: 8px 12px;
  padding: 6px 10px;
  border-radius: 10px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  background: rgba(2, 2, 10, 0.88);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.5), 0 0 0 1px rgba(255, 255, 255, 0.04);
  will-change: transform;
}

/* input row */
.search-input-wrap {
  display: flex;
  align-items: center;
  gap: 7px;
  flex: 1;
  min-width: 0;
}
.search-icon {
  color: rgba(255, 255, 255, 0.55);
  flex-shrink: 0;
}
.search-input {
  flex: 1;
  min-width: 0;
  background: transparent;
  border: none;
  outline: none;
  color: #f0f0f5;
  font-family: 'JetBrains Mono', 'Cascadia Code', 'Consolas', monospace;
  font-size: 13px;
  caret-color: #6eb5d9;
}
.search-input::placeholder {
  color: rgba(255, 255, 255, 0.3);
}

/* match counter */
.search-counter {
  font-family: 'JetBrains Mono', 'Cascadia Code', 'Consolas', monospace;
  font-size: 11px;
  color: rgba(255, 255, 255, 0.65);
  white-space: nowrap;
  flex-shrink: 0;
  min-width: 42px;
  text-align: right;
}

/* toggle buttons */
.search-toggle {
  padding: 3px 6px;
  border-radius: 5px;
  border: 1px solid rgba(255, 255, 255, 0.12);
  background: transparent;
  color: rgba(255, 255, 255, 0.5);
  font-family: 'JetBrains Mono', 'Cascadia Code', 'Consolas', monospace;
  font-size: 11px;
  cursor: pointer;
  transition: all 0.15s ease;
  flex-shrink: 0;
}
.search-toggle:hover {
  color: rgba(255, 255, 255, 0.85);
  border-color: rgba(255, 255, 255, 0.25);
  background: rgba(255, 255, 255, 0.06);
}
.search-toggle.active {
  color: #ffffff;
  border-color: rgba(255, 255, 255, 0.4);
  background: rgba(255, 255, 255, 0.1);
}

/* nav arrows */
.search-nav-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 26px;
  height: 26px;
  border-radius: 5px;
  border: none;
  background: transparent;
  color: rgba(255, 255, 255, 0.55);
  cursor: pointer;
  transition: all 0.15s ease;
  flex-shrink: 0;
}
.search-nav-btn:hover:not(:disabled) {
  color: #ffffff;
  background: rgba(255, 255, 255, 0.08);
}
.search-nav-btn:disabled {
  color: rgba(255, 255, 255, 0.12);
  cursor: default;
}

/* close button */
.search-close-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 26px;
  height: 26px;
  border-radius: 5px;
  border: none;
  background: transparent;
  color: rgba(255, 255, 255, 0.45);
  cursor: pointer;
  transition: all 0.15s ease;
  flex-shrink: 0;
}
.search-close-btn:hover {
  color: #ff6b6b;
  background: rgba(255, 107, 107, 0.1);
}

@keyframes search-slide-in {
  0%   { opacity: 0; transform: translate3d(0, -28px, 0); }
  100% { opacity: 1; transform: translate3d(0, 0, 0); }
}

/* --- Right sidebar slide-in --- */
.animate-slide-in-right {
  animation: slide-in-right 0.25s cubic-bezier(0.16, 1, 0.3, 1);
}
@keyframes slide-in-right {
  0%   { opacity: 0; transform: translate3d(60px, 0, 0); }
  100% { opacity: 1; transform: translate3d(0, 0, 0); }
}

/* --- Font-size toast --- */
.font-toast {
  animation: toast-pop-in 0.18s cubic-bezier(0.16, 1, 0.3, 1);
}
.font-toast.toast-out {
  animation: toast-fade-out 0.35s ease forwards;
}
.toast-badge {
  display: inline-block;
  padding: 6px 16px;
  border-radius: 20px;
  background: rgba(2, 2, 12, 0.82);
  border: 1px solid rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  color: #e0e0f0;
  font-family: 'JetBrains Mono', 'Cascadia Code', 'Consolas', monospace;
  font-size: 13px;
  user-select: none;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.45);
}
@keyframes toast-pop-in {
  0%   { opacity: 0; transform: translate3d(0, 6px, 0) scale(0.9); }
  100% { opacity: 1; transform: translate3d(0, 0, 0) scale(1); }
}
@keyframes toast-fade-out {
  0%   { opacity: 1; }
  100% { opacity: 0; }
}

/* --- Xterm.js overrides --- */
.xterm {
  padding: 8px 12px;
}
.xterm-screen {
  background: transparent !important;
}
.xterm-viewport {
  background: transparent !important;
}
.xterm-viewport::-webkit-scrollbar {
  width: 6px;
}
.xterm-viewport::-webkit-scrollbar-thumb {
  background: rgba(30, 30, 58, 0.6);
  border-radius: 3px;
}

import { useEffect, useRef, useState, useCallback } from 'react'
import { Terminal } from '@xterm/xterm'
import { FitAddon } from '@xterm/addon-fit'
import { WebLinksAddon } from '@xterm/addon-web-links'
import { SearchAddon } from '@xterm/addon-search'
import '@xterm/xterm/css/xterm.css'
import SearchBar from './SearchBar'
import useAudioEngine from '../hooks/useAudioEngine'

const COSMIC_THEME = {
  background: 'rgba(8, 8, 24, 0.08)',
  foreground: '#e0e0f0',
  cursor: '#6eb5d9',
  cursorAccent: '#06060f',
  selectionBackground: '#6eb5d944',
  selectionForeground: '#f0f0f8',
  black: '#1a1a2e',
  red: '#ff6b6b',
  green: '#66d9e8',
  yellow: '#ffd43b',
  blue: '#6eb5d9',
  magenta: '#da77f2',
  cyan: '#22b8cf',
  white: '#c8c8d8',
  brightBlack: '#4a4a6a',
  brightRed: '#ff8787',
  brightGreen: '#8ce8f0',
  brightYellow: '#ffe066',
  brightBlue: '#a78bfa',
  brightMagenta: '#e599f7',
  brightCyan: '#66d9e8',
  brightWhite: '#f0f0f8'
}

export default function TerminalCanvas({ activeSessionId, sessionName, onSessionCreated, musicEnabled = true, audioMap, masterVolume = 0.75, mode = 'dynamic', staticTier = 0, onTierChange }) {
  const containerRef = useRef(null)
  const termRef = useRef(null)
  const fitRef = useRef(null)
  const searchAddonRef = useRef(null)
  const buffersRef = useRef(new Map())   // sessionId → output string
  const shownIdRef = useRef(null)        // which session xterm is currently showing
  const fontSizeRef = useRef(14)         // live fontSize, avoids stale closures
  const toastTimerRef = useRef(null)

  const [searchOpen, setSearchOpen] = useState(false)
  const [fontSize, setFontSize] = useState(14)
  const [toast, setToast] = useState(null)  // { text, visible }

  const openSearch = useCallback(() => setSearchOpen(true), [])
  const closeSearch = useCallback(() => setSearchOpen(false), [])

  // Audio engine — 3-tier, IKD-driven
  const { updateTypingStrike, currentTier } = useAudioEngine(
    audioMap,
    { enabled: musicEnabled, masterVolume, mode, staticTier }
  )

  // Bubble tier changes up to App for UI display
  useEffect(() => { onTierChange?.(currentTier) }, [currentTier, onTierChange])

  function showToast(text) {
    if (toastTimerRef.current) clearTimeout(toastTimerRef.current)
    setToast({ text, visible: true })
    toastTimerRef.current = setTimeout(() => {
      setToast((prev) => prev ? { ...prev, visible: false } : null)
    }, 1200)
  }

  // Switch display to a different session
  function switchDisplay(toId) {
    const term = termRef.current
    if (!term) return

    const oldId = shownIdRef.current
    if (oldId === toId) return

    shownIdRef.current = toId

    term.reset()
    try { fitRef.current?.fit() } catch (_) {}

    const buf = buffersRef.current.get(toId) || ''
    if (buf) {
      term.write(buf)
    }
  }

  // Effect 1: Terminal lifecycle (mount once)
  useEffect(() => {
    const term = new Terminal({
      cursorBlink: true,
      cursorStyle: 'bar',
      fontSize: 14,
      fontFamily: 'JetBrainsMono NF, JetBrainsMonoNL NF, JetBrains Mono, Cascadia Code, Consolas, monospace',
      letterSpacing: 1,
      lineHeight: 1.5,
      theme: COSMIC_THEME,
      allowProposedApi: true,
      windowsMode: true
    })

    const fitAddon = new FitAddon()
    const searchAddon = new SearchAddon()
    term.loadAddon(fitAddon)
    term.loadAddon(new WebLinksAddon())
    term.loadAddon(searchAddon)
    searchAddonRef.current = searchAddon

    term.open(containerRef.current)
    fitAddon.fit()

    termRef.current = term
    fitRef.current = fitAddon

    // Global Ctrl+F → toggle search bar
    term.attachCustomKeyEventHandler((e) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'f') {
        e.preventDefault()
        setSearchOpen((v) => !v)
        return false
      }
      return true
    })

    // Forward keystrokes + feed IKD engine
    term.onData((data) => {
      updateTypingStrike()
      window.terminal.sendInput(data)
    })

    // Receive PTY output — route to correct buffer
    const unsubOutput = window.terminal.onOutput(({ sessionId, data }) => {
      // Always accumulate to the correct session's buffer
      const prev = buffersRef.current.get(sessionId) || ''
      buffersRef.current.set(sessionId, prev + data)

      // Write to screen if this session is shown, or no session established yet (initial load)
      if (sessionId === shownIdRef.current || shownIdRef.current === null) {
        term.write(data)
      }
    })

    // Handle PTY exit
    const unsubExit = window.terminal.onExit(({ id, exitCode }) => {
      term.write(`\r\n\x1b[33m[${id} exited with code ${exitCode}]\x1b[0m\r\n`)
    })

    // Handle auto-switch (exit / close of active session)
    const unsubSwitched = window.terminal.onSwitched((newId) => {
      if (newId) switchDisplay(newId)
    })

    // Ctrl+Wheel → font size + toast
    function handleWheel(e) {
      if (!e.ctrlKey) return
      e.preventDefault()
      e.stopPropagation()
      const next = Math.min(28, Math.max(10, fontSizeRef.current - Math.sign(e.deltaY)))
      if (next === fontSizeRef.current) return
      fontSizeRef.current = next
      term.options.fontSize = next
      setFontSize(next)
      showToast(`${next}px`)
      try { fitAddon.fit() } catch (_) {}
      // Note: we intentionally skip resizePty here.
      // Notifying PTY of dimension changes would cause pwsh to re-render
      // the current line, which gets appended to the session buffer and
      // creates duplicated content on repeated zoom in/out.
    }
    containerRef.current.addEventListener('wheel', handleWheel, { passive: false, capture: true })

    // Resize PTY when container changes
    const resizeObserver = new ResizeObserver(() => {
      try {
        fitAddon.fit()
        window.terminal.resizePty(term.cols, term.rows)
      } catch (_) {}
    })
    resizeObserver.observe(containerRef.current)

    // Create first PTY session
    window.terminal.createPty(term.cols, term.rows).then((session) => {
      if (session && onSessionCreated) {
        shownIdRef.current = session.id
        if (!buffersRef.current.has(session.id)) {
          buffersRef.current.set(session.id, '')
        }
        onSessionCreated(session)
      }
    })

    return () => {
      containerRef.current?.removeEventListener('wheel', handleWheel, { capture: true })
      clearTimeout(toastTimerRef.current)
      resizeObserver.disconnect()
      unsubOutput()
      unsubExit()
      unsubSwitched()
      term.dispose()
    }
  }, [])

  // Effect 2: React to session switch from App state (sidebar click / new session)
  useEffect(() => {
    if (activeSessionId && activeSessionId !== shownIdRef.current) {
      switchDisplay(activeSessionId)
    }
  }, [activeSessionId])

  const title = sessionName ? `${sessionName} — pwsh` : 'pwsh — galaxy-terminal'

  return (
    <div className="h-full flex flex-col bg-cosmos-bg/80 backdrop-blur-sm rounded-lg overflow-hidden border border-cosmos-border/50">
      <div className="terminal-chrome flex items-center gap-2 px-4 py-2 border-b border-cosmos-border/50 shrink-0">
        <div className="flex gap-1.5">
          <div className="w-3 h-3 rounded-full bg-red-500/80" />
          <div className="w-3 h-3 rounded-full bg-yellow-500/80" />
          <div className="w-3 h-3 rounded-full bg-cosmos-accent/70 shadow-[0_0_6px_rgba(110,181,217,0.5)]" />
        </div>
        <span className="text-sm text-cosmos-dim font-mono ml-2 truncate">{title}</span>
        <div className="ml-auto flex items-center gap-2 text-xs text-cosmos-dim font-mono shrink-0">
          <span className="animate-pulse text-cosmos-accent">●</span>
          <span>已连接</span>
        </div>
      </div>

      <div className="relative flex-1 min-h-0">
        {searchOpen && (
        <SearchBar
          searchAddon={searchAddonRef.current}
          term={termRef.current}
          onClose={closeSearch}
        />
        )}

        {toast && (
        <div
          className={`font-toast ${toast.visible ? 'toast-in' : 'toast-out'}`}
          style={{
            position: 'absolute',
            top: '50%',
            left: '50%',
            transform: 'translate(-50%, -50%)',
            zIndex: 30,
            pointerEvents: 'none'
          }}
        >
          <span className="toast-badge">{toast.text}</span>
        </div>
        )}

        <div ref={containerRef} className="w-full h-full" />
      </div>

      <div className="px-4 py-1.5 terminal-chrome border-t border-cosmos-border/50 flex items-center justify-between text-xs text-cosmos-dim font-mono shrink-0">
        <span>Galaxy Terminal · xterm</span>
        <div className="flex items-center gap-2">
          <span className="text-cosmos-accent">●</span>
          <span>UTF-8</span>
          <span>|</span>
          <span>pwsh</span>
        </div>
      </div>
    </div>
  )
}

import { useRef, useEffect, useMemo } from 'react'
import AnsiToHtml from 'ansi-to-html'
import CommandBlock from './CommandBlock'

const converter = new AnsiToHtml({
  fg: '#6b6b8a',
  bg: 'transparent',
  colors: {
    0: '#1a1a2e', 1: '#ff6b6b', 2: '#66d9e8', 3: '#ffd43b',
    4: '#7c6ff7', 5: '#da77f2', 6: '#22b8cf', 7: '#c8c8d8',
    8: '#4a4a6a', 9: '#ff8787', 10: '#8ce8f0', 11: '#ffe066',
    12: '#a78bfa', 13: '#e599f7', 14: '#66d9e8', 15: '#f0f0f8'
  }
})

export default function BlockList({ blocks, prelude }) {
  const bottomRef = useRef(null)

  const preludeHtml = useMemo(() => {
    if (!prelude) return null
    return converter.toHtml(prelude)
  }, [prelude])

  // Auto-scroll to bottom when blocks change
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [blocks])

  return (
    <div className="flex-1 overflow-y-auto py-4">
      {/* Prelude: pwsh banner / prompts before first command */}
      {preludeHtml && (
        <div
          className="mx-3 mb-3 px-4 py-2 text-sm font-mono leading-relaxed"
          style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-word' }}
          dangerouslySetInnerHTML={{ __html: preludeHtml }}
        />
      )}

      {blocks.map((block) => (
        <CommandBlock key={block.id} block={block} />
      ))}

      {/* Empty state */}
      {blocks.length === 0 && !prelude && (
        <div className="flex items-center justify-center h-full text-cosmos-dim/30 text-sm font-mono select-none">
          Ready — type a command below
        </div>
      )}

      <div ref={bottomRef} />
    </div>
  )
}

import { useMemo } from 'react'
import AnsiToHtml from 'ansi-to-html'

const converter = new AnsiToHtml({
  fg: '#e0e0f0',
  bg: 'transparent',
  colors: {
    0: '#1a1a2e',
    1: '#ff6b6b',
    2: '#66d9e8',
    3: '#ffd43b',
    4: '#7c6ff7',
    5: '#da77f2',
    6: '#22b8cf',
    7: '#c8c8d8',
    8: '#4a4a6a',
    9: '#ff8787',
    10: '#8ce8f0',
    11: '#ffe066',
    12: '#a78bfa',
    13: '#e599f7',
    14: '#66d9e8',
    15: '#f0f0f8'
  }
})

export default function CommandBlock({ block }) {
  const outputHtml = useMemo(() => {
    if (!block.output) return null
    return converter.toHtml(block.output)
  }, [block.output])

  return (
    <div className="command-block mx-3 mb-3 rounded-xl overflow-hidden border border-white/[0.06]"
         style={{ background: 'rgba(12, 12, 35, 0.45)', backdropFilter: 'blur(8px)' }}>
      {/* Command header */}
      <div className="flex items-center gap-2 px-4 py-2.5 border-b border-white/[0.04]"
           style={{ background: 'rgba(8, 8, 24, 0.3)' }}>
        <span className="text-cosmos-accent text-xs font-mono shrink-0">{'>'}</span>
        <span className="text-sm text-cosmos-text/90 font-mono truncate">{block.input}</span>
        {block.status === 'running' && (
          <span className="ml-auto w-2 h-2 rounded-full bg-cosmos-accent animate-pulse shrink-0" />
        )}
        {block.status === 'interrupted' && (
          <span className="ml-auto text-[10px] text-yellow-400/70 shrink-0">^C</span>
        )}
        {block.status === 'completed' && (
          <span className="ml-auto w-2 h-2 rounded-full bg-cosmos-accent/50 shadow-[0_0_4px_rgba(110,181,217,0.4)] shrink-0" />
        )}
      </div>

      {/* Output body */}
      {outputHtml && (
        <div
          className="px-4 py-2.5 text-sm font-mono leading-relaxed overflow-x-auto"
          style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-word' }}
          dangerouslySetInnerHTML={{ __html: outputHtml }}
        />
      )}
    </div>
  )
}

import bgImage from '../assets/Snipaste_2026-05-17_11-45-36.png'
import Starfield from './Starfield'

export default function GalaxyBackground({ showScanLine = true }) {
  return (
    <>
      <div
        className="galaxy-layer absolute inset-0 bg-cover bg-center bg-no-repeat opacity-60"
