import { useState, useCallback, useRef, useEffect } from 'react'

/* ================================================================== */
/*  Spotify Web API controller                                         */
/*                                                                     */
/*  TOKEN EXCHANGE HAPPENS IN MAIN PROCESS (bypasses CSP)              */
/* ================================================================== */

const CLIENT_ID = 'fa0592f0132346f8bcd7f28a3f8438f7'
const REDIRECT_URI = 'http://127.0.0.1:8000/callback'
const SCOPES = 'streaming user-read-playback-state user-modify-playback-state'

function spotifyApi(path, token, opts = {}) {
  return fetch(`https://api.spotify.com/v1${path}`, {
    headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
    ...opts
  }).then((r) => (r.status === 204 ? null : r.json()))
}

/* ---- PKCE helpers ---- */

function generateCodeVerifier() {
  const arr = new Uint8Array(64)
  crypto.getRandomValues(arr)
  return btoa(String.fromCharCode(...arr)).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '')
}

async function generateCodeChallenge(verifier) {
  const digest = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(verifier))
  return btoa(String.fromCharCode(...new Uint8Array(digest))).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '')
}

/* ================================================================== */
/*  Hook                                                               */
/* ================================================================== */

export default function useSpotifyController() {
  const [results, setResults] = useState([])
  const [searching, setSearching] = useState(false)
  const [connected, setConnected] = useState(false)
  const [connecting, setConnecting] = useState(false)
  const [error, setError] = useState(null)
  const [deviceId, setDeviceId] = useState(null)
  const tokenRef = useRef(sessionStorage.getItem('spotify_token') || null)
  const deviceRef = useRef(null)

  // Auto-check existing token on mount
  useEffect(() => {
    if (tokenRef.current) setConnected(true)
  }, [])

  // Listen for token events pushed from main process (backup channel)
  useEffect(() => {
    const u1 = window.terminal?.onSpotifyTokenSuccess?.(({ access_token, refresh_token }) => {
      console.log('🚀🚀🚀 [Renderer] Token success from main:', access_token?.slice(0, 15) + '...')
      tokenRef.current = access_token
      sessionStorage.setItem('spotify_token', access_token)
      if (refresh_token) sessionStorage.setItem('spotify_refresh', refresh_token)
      setConnected(true)
      setConnecting(false)
      setError(null)
    })
    const u2 = window.terminal?.onSpotifyTokenError?.((msg) => {
      console.error('❌❌❌ [Renderer] Token error from main:', msg)
      setError(msg)
      setConnecting(false)
    })
    return () => { u1?.(); u2?.() }
  }, [])

  /* ---- OAuth connect ---- */
  const connect = useCallback(async () => {
    if (!CLIENT_ID) { setError('Client ID not set'); return false }
    setConnecting(true)
    setError(null)

    // Try refresh first (via main process to avoid CSP)
    const refreshToken = sessionStorage.getItem('spotify_refresh')
    if (refreshToken) {
      try {
        const j = await window.terminal?.refreshSpotifyToken?.({ refreshToken, clientId: CLIENT_ID })
        if (j?.access_token) {
          tokenRef.current = j.access_token
          sessionStorage.setItem('spotify_token', j.access_token)
          if (j.refresh_token) sessionStorage.setItem('spotify_refresh', j.refresh_token)
          setConnected(true)
          setConnecting(false)
          return true
        }
        // Refresh failed — clear and re-auth
        sessionStorage.removeItem('spotify_refresh')
        sessionStorage.removeItem('spotify_token')
        console.log('[Spotify] Refresh expired, starting full OAuth...')
      } catch (_) {}
    }

    // Full PKCE OAuth → main process handles EVERYTHING
    const verifier = generateCodeVerifier()
    const challenge = await generateCodeChallenge(verifier)

    const params = new URLSearchParams({
      client_id: CLIENT_ID, response_type: 'code', redirect_uri: REDIRECT_URI,
      code_challenge_method: 'S256', code_challenge: challenge, scope: SCOPES
    })
    const authUrl = `https://accounts.spotify.com/authorize?${params}`
    console.log('[Spotify] Opening auth window (main process handles token)...')

    // Main process: opens window → captures code → exchanges token → returns result
    let result
    try {
      result = await window.terminal?.openSpotifyAuth?.({
        authUrl, clientId: CLIENT_ID, redirectUri: REDIRECT_URI, codeVerifier: verifier
      })
    } catch (e) {
      console.error('[Spotify] IPC error:', e)
      setError('IPC error: ' + e.message)
      setConnecting(false)
      return false
    }

    console.log('🚀🚀🚀 [Renderer] Auth result:', result?.access_token ? '✅ TOKEN OK' : result?.error ? `❌ ${result.error}` : '❓ empty')

    if (result?.access_token) {
      tokenRef.current = result.access_token
      sessionStorage.setItem('spotify_token', result.access_token)
      if (result.refresh_token) sessionStorage.setItem('spotify_refresh', result.refresh_token)
      setConnected(true)
      setConnecting(false)
      setError(null)
      return true
    }

    if (result?.error) setError(result.error)
    else setError('No token received')
    setConnecting(false)
    return false
  }, [])

  /* ---- search ---- */
  const search = useCallback(async (query) => {
    if (!query.trim() || !tokenRef.current) return
    setSearching(true)
    try {
      const data = await spotifyApi(`/search?q=${encodeURIComponent(query)}&type=track&limit=20`, tokenRef.current)
      const tracks = (data?.tracks?.items || []).map((t) => ({
        id: t.id, uri: t.uri, name: t.name,
        artist: t.artists.map((a) => a.name).join(', '),
        album: t.album?.name, duration: t.duration_ms,
        image: t.album?.images?.[2]?.url
      }))
      setResults(tracks)
    } catch (_) { setResults([]) }
    setSearching(false)
  }, [])

  /* ---- device ---- */
  const fetchDevices = useCallback(async () => {
    if (!tokenRef.current) return null
    try {
      const data = await spotifyApi('/me/player/devices', tokenRef.current)
      const devices = data?.devices || []
      const desktop = devices.find((d) => d.type === 'Computer') || devices[0]
      if (desktop) { deviceRef.current = desktop.id; setDeviceId(desktop.id) }
      return desktop?.id || null
    } catch (_) { return null }
  }, [])

  /* ---- play ---- */
  const play = useCallback(async (uri) => {
    if (!tokenRef.current) return false
    const did = deviceRef.current || (await fetchDevices())
    if (!did) { console.warn('[Spotify] No active device — open Spotify desktop'); return false }
    try {
      await spotifyApi('/me/player/play', tokenRef.current, {
        method: 'PUT', body: JSON.stringify({ uris: [uri], device_id: did })
      })
      return true
    } catch (_) { return false }
  }, [fetchDevices])

  /* ---- pause ---- */
  const pause = useCallback(async () => {
    if (!tokenRef.current) return
    try { await spotifyApi('/me/player/pause', tokenRef.current, { method: 'PUT' }) } catch (_) {}
  }, [])

  return { connect, connected, connecting, error, deviceId, search, results, searching, play, pause }
}

import { useEffect, useRef, useCallback, useState } from 'react'

/* ================================================================== */
/*  Constants                                                          */
/* ================================================================== */

const POLL_MS        = 100      // state-check tick
const FADE_OUT_S     = 0.8      // old-track exponential fade-out
const FADE_IN_S      = 1.0      // new-track exponential fade-in
const FADE_MUTE_S    = 0.5
const EPS            = 0.001
const MIN_STATE_MS   = 1200     // minimum time before allowing another auto-switch

// IKD noise gate — delta below this is key-repeat / sticky-key junk
const NOISE_DELTA_MS = 150

// Fast-typing threshold for streak counting (delta < 600ms ≈ WPM > 100)
const FAST_DELTA_MS  = 600
const FAST_STREAK_N  = 5        // consecutive fast strikes required for Climax

// Asymmetric EMA — slow climb, inertial decay
const EMA_RISE       = 0.2
const EMA_FALL       = 0.1
const EMA_DECAY      = 0.04     // per-tick decay when idle > 600ms

// 3 tiers with high-entry low-exit hysteresis
const TIER_IDLE      = 0
const TIER_ACTIVE    = 1
const TIER_CLIMAX    = 2

const CLIMAX_ENTER   = 90       // smoothed WPM must exceed this to enter Climax
const CLIMAX_EXIT    = 70       // smoothed WPM must drop below this to leave Climax
const IDLE_ENTER     = 2        // smoothed WPM ≤ this → Idle

const GAIN_BASE = [0.55, 0.75, 1.0]

/* ================================================================== */
/*  Singleton AudioContext                                             */
/* ================================================================== */

let _ctx = null
function getCtx() {
  if (!_ctx) _ctx = new AudioContext()
  if (_ctx.state === 'suspended') _ctx.resume()
  return _ctx
}

/* ================================================================== */
/*  Exponential ramp helper                                            */
/* ================================================================== */

function expRampTo(gain, target, dur) {
  const ctx = _ctx
  if (!ctx) return
  const now = ctx.currentTime
  gain.gain.cancelScheduledValues(now)
  gain.gain.setValueAtTime(gain.gain.value, now)
  gain.gain.exponentialRampToValueAtTime(Math.max(EPS, target), now + dur)
}

/* ================================================================== */
/*  Tier decision                                                      */
/* ================================================================== */

function decideTier(smoothed, prevTier, fastStreak) {
  if (smoothed <= IDLE_ENTER) return TIER_IDLE

  // Enter Climax: must exceed 90 AND have 5+ consecutive fast strikes
  if (smoothed > CLIMAX_ENTER && fastStreak >= FAST_STREAK_N) return TIER_CLIMAX

  // Stay in Climax (hysteresis): exit only below 70
  if (prevTier === TIER_CLIMAX && smoothed >= CLIMAX_EXIT) return TIER_CLIMAX

  return TIER_ACTIVE
}

/* ================================================================== */
/*  Hook                                                               */
/* ================================================================== */

export default function useAudioEngine(audioMap, {
  enabled = true,
  masterVolume = 0.75,
  mode = 'dynamic',
  staticTier = 0
} = {}) {
  /* ---- IKD state ---- */
  const lastStrikeRef   = useRef(0)       // ms timestamp of previous valid keystroke
  const fastStreakRef   = useRef(0)       // consecutive strikes with delta < FAST_DELTA_MS
  const smoothedRef     = useRef(0)       // EMA-smoothed WPM

  /* ---- audio state ---- */
  const gainsRef        = useRef(null)
  const elemsRef        = useRef(null)
  const tierRef         = useRef(TIER_IDLE)
  const lastSwitchRef   = useRef(0)
  const intervalRef     = useRef(null)
  const enabledRef      = useRef(enabled)
  const masterRef       = useRef(masterVolume)
  const modeRef         = useRef(mode)
  const audioMapRef     = useRef(audioMap)
  const xfadeIdRef      = useRef(0)
  enabledRef.current    = enabled
  masterRef.current     = masterVolume
  modeRef.current       = mode
  audioMapRef.current   = audioMap

  const [currentTier, setCurrentTier] = useState(TIER_IDLE)

  function targetGain(tier) { return GAIN_BASE[tier] * masterRef.current }

  /* ----- crossfade ----- */
  function crossfadeTo(from, to) {
    const ctx = _ctx
    if (!ctx) return
    const gains = gainsRef.current
    const elems = elemsRef.current
    if (!gains || !elems) return
    if (from === to) return

    const xid = ++xfadeIdRef.current

    if (from >= 0) {
      expRampTo(gains[from], 0, FADE_OUT_S)
      setTimeout(() => {
        if (xfadeIdRef.current !== xid) return
        try {
          gains[from].gain.setValueAtTime(0, _ctx?.currentTime ?? 0)
          elems[from].pause()
        } catch (_) {}
      }, FADE_OUT_S * 1000 + 60)
    }

    elems[to].currentTime = 0
    elems[to].play().catch(() => {})
    expRampTo(gains[to], targetGain(to), FADE_IN_S)
  }

  function applyMasterVolume() {
    const gains = gainsRef.current
    if (!gains) return
    expRampTo(gains[tierRef.current], targetGain(tierRef.current), 0.3)
  }

  /* ----- mute / unmute ----- */
  const muteAll = useCallback(() => {
    const gains = gainsRef.current
    const elems = elemsRef.current
    if (!gains || !elems) return
    for (let i = 0; i < 3; i++) expRampTo(gains[i], 0, FADE_MUTE_S)
    setTimeout(() => {
      elems.forEach((el) => { try { el.pause() } catch (_) {} })
    }, FADE_MUTE_S * 1000 + 80)
    if (intervalRef.current) { clearInterval(intervalRef.current); intervalRef.current = null }
  }, [])

  const unmuteAll = useCallback(() => {
    const gains = gainsRef.current
    const elems = elemsRef.current
    if (!gains || !elems) return
    const tier = tierRef.current
    elems[tier].currentTime = 0
    elems[tier].play().catch(() => {})
    expRampTo(gains[tier], targetGain(tier), FADE_MUTE_S)
    if (modeRef.current === 'dynamic' && !intervalRef.current) startPoll()
  }, [])

  /* ================================================================== */
  /*  IKD Engine — poll loop                                            */
  /* ================================================================== */

  function startPoll() {
    if (!_ctx || !gainsRef.current) return
    intervalRef.current = setInterval(() => {
      if (!enabledRef.current || modeRef.current !== 'dynamic') return

      const nowTs = Date.now()
      let smoothed = smoothedRef.current

      // --- decay: if no strike for >600ms, slowly bleed WPM toward 0 ---
      const idleMs = nowTs - lastStrikeRef.current
      if (idleMs > 600 && smoothed > 0) {
        smoothed = smoothed * (1 - EMA_DECAY)
        if (smoothed < 0.5) { smoothed = 0; fastStreakRef.current = 0 }
        smoothedRef.current = smoothed
      }

      // --- tier decision ---
      const prevTier = tierRef.current
      const nextTier = decideTier(smoothed, prevTier, fastStreakRef.current)

      if (nextTier !== prevTier && nowTs - lastSwitchRef.current >= MIN_STATE_MS) {
        lastSwitchRef.current = nowTs
        tierRef.current = nextTier
        setCurrentTier(nextTier)
        crossfadeTo(prevTier, nextTier)
      }
    }, POLL_MS)
  }

  /* ================================================================== */
  /*  IKD Engine — keystroke handler (called from term.onData)          */
  /* ================================================================== */

  const updateTypingStrike = useCallback(() => {
    if (!enabledRef.current || modeRef.current !== 'dynamic') return

    const now = Date.now()
    const prev = lastStrikeRef.current
    lastStrikeRef.current = now

    if (prev === 0) return  // first strike — no delta yet

    const delta = now - prev
    const prevSmooth = smoothedRef.current

    let instantWpm

    if (delta < NOISE_DELTA_MS) {
      // Key-repeat / sticky-key noise — clamp to current smoothed value
      // so this event cannot pull the curve upward
      instantWpm = prevSmooth
      // Noise breaks the fast streak
      fastStreakRef.current = 0
    } else {
      // IKD → instantaneous WPM  (e.g. delta=500ms → 120 WPM)
      instantWpm = 60000 / delta

      // Fast streak tracking
      if (delta < FAST_DELTA_MS) {
        fastStreakRef.current++
      } else {
        fastStreakRef.current = 0
      }
    }

    // Asymmetric EMA — slow climb, inertial decay
    const alpha = instantWpm >= prevSmooth ? EMA_RISE : EMA_FALL
    const nextSmooth = instantWpm * alpha + prevSmooth * (1 - alpha)
    smoothedRef.current = nextSmooth
  }, [])

  /* ================================================================== */
  /*  Init / destroy / react effects (unchanged)                         */
  /* ================================================================== */

  useEffect(() => {
    const ctx = getCtx()
    const map = audioMapRef.current

    const elems = [0, 1, 2].map((i) => {
      const a = new Audio(map[i])
      a.loop = true; a.preload = 'auto'
      return a
    })
    elemsRef.current = elems

    const gains = elems.map((el) => {
      const src = ctx.createMediaElementSource(el)
      const g = ctx.createGain()
      g.gain.value = 0
      src.connect(g); g.connect(ctx.destination)
      return g
    })
    gainsRef.current = gains

    if (enabledRef.current) {
      elems[TIER_IDLE].play().catch(() => {})
      expRampTo(gains[TIER_IDLE], targetGain(TIER_IDLE), FADE_IN_S)
      tierRef.current = TIER_IDLE
      smoothedRef.current = 0
      if (modeRef.current === 'dynamic') startPoll()
    }

    return () => {
      clearInterval(intervalRef.current); intervalRef.current = null
      if (!ctx) return
      const now = ctx.currentTime
      gains.forEach((g) => {
        g.gain.cancelScheduledValues(now)
        g.gain.setValueAtTime(g.gain.value, now)
        g.gain.exponentialRampToValueAtTime(EPS, now + 0.15)
      })
      setTimeout(() => {
        elems.forEach((el) => { el.pause(); el.src = '' })
        gains.forEach((g) => g.disconnect())
      }, 200)
      ctx.close().catch(() => {})
      _ctx = null; gainsRef.current = null; elemsRef.current = null
    }
  }, [])

  useEffect(() => {
    const elems = elemsRef.current, gains = gainsRef.current
    if (!elems || !gains) return
    for (let i = 0; i < 3; i++) {
      if (audioMap[i] && audioMap[i] !== elems[i].src) {
        const isActive = tierRef.current === i
        if (isActive) {
          expRampTo(gains[i], 0, FADE_OUT_S)
          setTimeout(() => {
            try { gains[i].gain.setValueAtTime(0, _ctx?.currentTime ?? 0) } catch (_) {}
            elems[i].src = audioMap[i]; elems[i].load()
            elems[i].currentTime = 0; elems[i].play().catch(() => {})
            expRampTo(gains[i], targetGain(i), FADE_IN_S)
          }, FADE_OUT_S * 1000 + 50)
        } else {
          elems[i].src = audioMap[i]; elems[i].load()
          if (!elems[i].paused) { elems[i].currentTime = 0; elems[i].play().catch(() => {}) }
        }
      }
    }
  }, [audioMap[0], audioMap[1], audioMap[2]])

  useEffect(() => {
    if (!gainsRef.current || !elemsRef.current) return
    if (enabled) unmuteAll(); else muteAll()
  }, [enabled, muteAll, unmuteAll])

  useEffect(() => {
    if (!gainsRef.current || !elemsRef.current) return
    applyMasterVolume()
  }, [masterVolume])

  useEffect(() => {
    if (!gainsRef.current || !elemsRef.current) return
    if (mode === 'static') {
      if (intervalRef.current) { clearInterval(intervalRef.current); intervalRef.current = null }
      const prev = tierRef.current
      if (staticTier !== prev) {
        tierRef.current = staticTier; setCurrentTier(staticTier)
        crossfadeTo(prev, staticTier)
      }
    } else {
      if (!intervalRef.current && enabledRef.current) startPoll()
    }
  }, [mode, staticTier])

  return { updateTypingStrike, currentTier }
}

import { useState, useRef, useEffect } from 'react'

const TIER_NAMES = ['Deep Space', 'Particle Stream', 'Interstellar']

function fileName(url) {
  if (!url) return '—'
  try { return decodeURIComponent(url.split('/').pop()) } catch (_) { return url }
}

export default function TopMenuBar({
  currentTime = '',
  musicOn,
  onToggleMusic,
  currentTier = 0,
  audioMap = {},
  masterVolume = 0.75,
  mode = 'dynamic',
  onChangeTrack,
  onVolumeChange,
  onModeChange,
  onStaticSelect,
  onToggleSearch,
  searchOpen,
  musicPlaying,
  musicTrack,
  onMusicPause,
  onMusicResume
}) {
  const [audioOpen, setAudioOpen] = useState(false)
  const panelRef = useRef(null)
  const fileRefs = useRef([null, null, null])

  useEffect(() => {
    if (!audioOpen) return
    function handler(e) {
      if (panelRef.current && !panelRef.current.contains(e.target)) setAudioOpen(false)
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [audioOpen])

  function handleFile(tier, e) {
    const file = e.target.files?.[0]
    if (file) onChangeTrack?.(tier, file)
    e.target.value = ''
  }

  const isStatic = mode === 'static'

  return (
    <div
      className="h-12 glass-panel border-b border-cosmos-border/30 flex items-center justify-between px-4 shrink-0 relative"
      style={{ WebkitAppRegion: 'drag' }}
    >
      {/* 左侧：音乐搜索 + 播放 */}
      <div className="flex items-center gap-3" style={{ WebkitAppRegion: 'no-drag' }}>
        <button
          type="button"
          onClick={onToggleSearch}
          className={`flex items-center gap-2 rounded-full px-3 py-1.5 transition-all duration-300 border ${
            searchOpen
              ? 'bg-cosmos-accent/15 border-cosmos-accent/40 text-cosmos-accent'
              : 'bg-cosmos-panel/50 border-cosmos-border/40 text-cosmos-dim hover:text-cosmos-text'
          }`}
        >
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
            <circle cx="11" cy="11" r="8" /><path d="m21 21-4.35-4.35" />
          </svg>
          <span className="text-xs uppercase tracking-wider font-mono">Music</span>
          {searchOpen && (
            <span className="w-1.5 h-1.5 rounded-full bg-cosmos-accent shadow-[0_0_6px_#6eb5d9]" />
          )}
        </button>

        {musicTrack && (
          <div className="flex items-center gap-1 bg-cosmos-panel/40 rounded-full px-2 py-1 border border-cosmos-border/30">
            <button
              type="button"
              className="p-1.5 hover:bg-cosmos-panel/60 rounded-full transition-colors"
              onClick={musicPlaying ? onMusicPause : onMusicResume}
              title={musicPlaying ? 'Pause' : 'Play'}
            >
              {musicPlaying ? (
                <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor" className="text-cosmos-accent">
                  <rect x="6" y="4" width="4" height="16" /><rect x="14" y="4" width="4" height="16" />
                </svg>
              ) : (
                <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor" className="text-cosmos-accent">
                  <polygon points="5 3 19 12 5 21 5 3" />
                </svg>
              )}
            </button>
          </div>
        )}

        {musicTrack && (
          <div className="hidden sm:flex items-center gap-2 text-xs max-w-[200px]">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="text-cosmos-accent shrink-0 animate-pulse">
              <path d="M9 18V5l12-2v13" /><circle cx="6" cy="18" r="3" /><circle cx="18" cy="16" r="3" />
            </svg>
            <span className="text-cosmos-dim truncate font-mono">
              {musicTrack.name} — {musicTrack.artist}
            </span>
          </div>
        )}
      </div>

      {/* 中间：时钟 */}
      <div className="absolute left-1/2 -translate-x-1/2 flex items-center gap-3 pointer-events-none">
        <div className="flex items-center gap-2 bg-cosmos-panel/50 rounded-full px-4 py-1.5 border border-cosmos-border/30">
          <div className="w-5 h-5 rounded bg-gradient-to-br from-cosmos-accent/80 to-cosmos-accent2/80 flex items-center justify-center">
            <span className="text-[10px] font-bold text-white">G</span>
          </div>
          <span className="text-sm text-cosmos-text/80 font-mono">~</span>
          <span className="text-xs text-cosmos-dim mx-1">|</span>
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="text-cosmos-dim">
            <circle cx="12" cy="12" r="10" /><path d="M12 6v6l4 2" strokeLinecap="round" />
          </svg>
          <span className="text-sm font-mono text-cosmos-text/80">{currentTime}</span>
        </div>
      </div>

      {/* 右侧：音量 + AUDIO */}
      <div className="flex items-center gap-4" style={{ WebkitAppRegion: 'no-drag' }}>
        <div className="hidden md:flex items-center gap-2 group">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="text-cosmos-dim">
            <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5" />
            <path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07" strokeLinecap="round" />
          </svg>
          <div className="w-0 overflow-hidden group-hover:w-20 transition-all duration-300">
            <input
              type="range"
              min="0"
              max="100"
              value={Math.round(masterVolume * 100)}
              onChange={(e) => onVolumeChange?.(Number(e.target.value) / 100)}
              className="w-full h-1 bg-cosmos-border/50 rounded-full appearance-none cursor-pointer accent-cosmos-accent"
            />
          </div>
        </div>

        <button
          type="button"
          onClick={() => setAudioOpen((v) => !v)}
          className={`flex items-center gap-1.5 text-xs uppercase tracking-wider font-mono transition-colors ${
            audioOpen ? 'text-cosmos-accent' : 'text-cosmos-accent/80 hover:text-cosmos-accent'
          }`}
        >
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <path d="M9 18V5l12-2v13" /><circle cx="6" cy="18" r="3" /><circle cx="18" cy="16" r="3" />
          </svg>
          <span>Audio</span>
          <span className="text-cosmos-dim">▾</span>
        </button>

        {audioOpen && (
          <div
            ref={panelRef}
            className="absolute top-12 right-4 z-50 w-[340px] p-4 rounded-xl border border-cosmos-border/40 glass-panel shadow-2xl font-mono max-h-[calc(100vh-56px)] overflow-y-auto"
          >
            <div className="flex items-center justify-between mb-3">
              <span className="text-[11px] font-semibold text-cosmos-accent tracking-widest">AUDIO</span>
              <button
                type="button"
                onClick={onToggleMusic}
                className={`px-2.5 py-0.5 rounded-full text-[10px] border ${
                  musicOn
                    ? 'border-cosmos-accent/35 bg-cosmos-accent/12 text-cosmos-accent'
                    : 'border-red-500/30 bg-red-500/10 text-red-400'
                }`}
              >
                {musicOn ? 'ON' : 'MUTE'}
              </button>
            </div>

            <div className="flex gap-1.5 mb-3">
              <button
                type="button"
                onClick={() => onModeChange?.('dynamic')}
                className={`flex-1 py-1.5 rounded-md text-[10px] border transition-colors ${
                  !isStatic ? 'border-cosmos-accent/35 bg-cosmos-accent/15 text-cosmos-accent' : 'border-cosmos-border/30 text-cosmos-dim'
                }`}
              >
                Dynamic
              </button>
              <button
                type="button"
                onClick={() => onModeChange?.('static')}
                className={`flex-1 py-1.5 rounded-md text-[10px] border transition-colors ${
                  isStatic ? 'border-cosmos-accent/35 bg-cosmos-accent/15 text-cosmos-accent' : 'border-cosmos-border/30 text-cosmos-dim'
                }`}
              >
                Static
              </button>
            </div>

            {TIER_NAMES.map((name, i) => {
              const active = i === currentTier && musicOn
              return (
                <div
                  key={i}
                  onClick={() => isStatic && onStaticSelect?.(i)}
                  className={`flex items-center gap-2 px-2.5 py-2 rounded-lg mb-1 border cursor-${isStatic ? 'pointer' : 'default'} ${
                    active ? 'bg-cosmos-accent/12 border-cosmos-accent/25' : 'bg-cosmos-panel/30 border-cosmos-border/20'
                  }`}
                >
                  <span className={`w-5 h-5 rounded flex items-center justify-center text-[10px] font-semibold ${
                    active ? 'bg-cosmos-accent/25 text-cosmos-accent' : 'bg-cosmos-panel text-cosmos-dim'
                  }`}>
                    {i + 1}
                  </span>
                  <div className="flex-1 min-w-0">
                    <div className={`text-[11px] ${active ? 'text-cosmos-text' : 'text-cosmos-dim'}`}>{name}</div>
                    <div className="text-[9px] text-cosmos-dim/60 truncate">{fileName(audioMap[i])}</div>
                  </div>
                  {active && <span className="w-1.5 h-1.5 rounded-full bg-cosmos-accent shadow-[0_0_6px_#6eb5d9]" />}
                  <button
                    type="button"
                    onClick={(e) => { e.stopPropagation(); fileRefs.current[i]?.click() }}
                    className="text-[9px] px-2 py-0.5 rounded border border-cosmos-border/30 text-cosmos-dim hover:text-cosmos-accent hover:border-cosmos-accent/30"
                  >
                    Change
                  </button>
                  <input ref={(el) => { fileRefs.current[i] = el }} type="file" accept="audio/*,.mp3,.wav,.ogg,.flac" className="hidden" onChange={(e) => handleFile(i, e)} />
                </div>
              )
            })}

            <div className="flex items-center gap-2 mt-2 pt-2 border-t border-cosmos-border/20">
              <input
                type="range"
                min="0"
                max="100"
                value={Math.round(masterVolume * 100)}
                onChange={(e) => onVolumeChange?.(Number(e.target.value) / 100)}
                className="flex-1 h-1 accent-cosmos-accent cursor-pointer"
              />
              <span className="text-[10px] text-cosmos-dim w-8 text-right">{Math.round(masterVolume * 100)}%</span>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

