  const [activeId, setActiveId] = useState(null)
  const [musicOn, setMusicOn] = useState(true)
  const [masterVolume, setMasterVolume] = useState(0.75)
  const [currentTier, setCurrentTier] = useState(0)
  const [audioMode, setAudioMode] = useState('dynamic')
  const [staticTier, setStaticTier] = useState(0)
  const [audioMap, setAudioMap] = useState({ 0: idleSrc, 1: activeSrc, 2: climaxSrc })
  const [searchOpen, setSearchOpen] = useState(false)
  const [currentTime, setCurrentTime] = useState('')
  const [showScanLine, setShowScanLine] = useState(true)

  const music = useMusicController()

  useEffect(() => {
    const updateTime = () => {
      setCurrentTime(
        new Date().toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' })
      )
    }
    updateTime()
    const interval = setInterval(updateTime, 1000)
    return () => clearInterval(interval)
  }, [])

  function handleChangeTrack(tier, file) {
    const url = URL.createObjectURL(file)
    setAudioMap((prev) => {
      const old = prev[tier]
      if (old && old.startsWith('blob:')) URL.revokeObjectURL(old)
      return { ...prev, [tier]: url }
    })
  }

  const handleSessionCreated = useCallback((session) => {
    setSessions((prev) => [...prev, session])
    setActiveId(session.id)
  }, [])

  const handleNewSession = useCallback(async () => {
    const session = await window.terminal.createPty(120, 30)
    if (session) {
      setSessions((prev) => [...prev, session])
      setActiveId(session.id)
    }
  }, [])

  const handleSwitch = useCallback(async (id) => {
    const ok = await window.terminal.switchSession(id)
    if (ok) setActiveId(id)
  }, [])

  const handleRename = useCallback(async (id, name) => {
    const ok = await window.terminal.renameSession(id, name)
    if (ok) {
      setSessions((prev) => prev.map((s) => (s.id === id ? { ...s, name } : s)))
    }
  }, [])

  const handleClose = useCallback(async (id) => {
    const ok = await window.terminal.closeSession(id)
    if (ok) {
      setSessions((prev) => {
        const next = prev.filter((s) => s.id !== id)
        if (activeId === id) {
          const newActive = next.length > 0 ? next[0].id : null
          if (newActive) window.terminal.switchSession(newActive)
          setActiveId(newActive)
        }
        return next
      })
    }
  }, [activeId])

  useEffect(() => {
    const unsub = window.terminal.onSwitched?.((newId) => {
      setActiveId(newId)
    })
    return () => { if (unsub) unsub() }
  }, [])

  useEffect(() => {
    const u1 = window.terminal.onMenuNewSession?.(() => handleNewSession())
    const u2 = window.terminal.onMenuCloseSession?.(() => {
      if (activeId) handleClose(activeId)
    })
    const u3 = window.terminal.onMenuToggleMusic?.(() => setMusicOn((v) => !v))
    return () => { u1?.(); u2?.(); u3?.() }
  }, [activeId, handleNewSession, handleClose])

  const handleToggleMusic = useCallback(() => setMusicOn((v) => !v), [])

  const activeSession = sessions.find((s) => s.id === activeId)

  return (
    <div className="relative h-screen w-full overflow-hidden bg-cosmos-bg">
      {splash && <SplashScreen onDone={() => setSplash(false)} />}
      <GalaxyBackground showScanLine={showScanLine} />

      <div className="relative z-10 h-full flex flex-col">
        <TopMenuBar
          currentTime={currentTime}
          musicOn={musicOn}
          onToggleMusic={handleToggleMusic}
          currentTier={currentTier}
          audioMap={audioMap}
          masterVolume={masterVolume}
          mode={audioMode}
          onChangeTrack={handleChangeTrack}
          onVolumeChange={setMasterVolume}
          onModeChange={setAudioMode}
          onStaticSelect={setStaticTier}
          onToggleSearch={() => setSearchOpen((v) => !v)}
          searchOpen={searchOpen}
          musicPlaying={music.playing}
          musicTrack={music.currentTrack}
          onMusicPause={music.pause}
          onMusicResume={music.resume}
        />

        <div className="flex-1 flex overflow-hidden min-h-0">
          <SessionList
            sessions={sessions}
            activeId={activeId}
            onSwitch={handleSwitch}
            onRename={handleRename}
            onClose={handleClose}
            onNew={handleNewSession}
          />

          <div className="flex-1 p-4 overflow-hidden min-w-0">
            <TerminalCanvas
              activeSessionId={activeId}
              sessionName={activeSession?.name}
              onSessionCreated={handleSessionCreated}
              musicEnabled={musicOn && !splash}
              audioMap={audioMap}
              masterVolume={masterVolume}
              mode={audioMode}
              staticTier={staticTier}
              onTierChange={setCurrentTier}
            />
          </div>

          <RightMusicSidebar
            visible={searchOpen}
            onClose={() => setSearchOpen(false)}
            results={music.results}
            searching={music.searching}
            onSearch={music.search}
            onPlay={music.play}
            currentTrack={music.currentTrack}
            error={music.error}
          />
        </div>

        <div className="h-7 glass-panel border-t border-cosmos-border/30 flex items-center justify-between px-4 text-xs shrink-0">
          <div className="flex items-center gap-4 text-cosmos-dim font-mono">
            <span className="flex items-center gap-1.5">
              <span className="w-2 h-2 rounded-full bg-cosmos-accent animate-pulse shadow-[0_0_8px_rgba(110,181,217,0.6)]" />
              {sessions.length} 个会话
            </span>
            <span>·</span>
            <span>当前: {activeSession?.name ?? '—'}</span>
          </div>
          <div className="flex items-center gap-4 text-cosmos-dim font-mono">
            <button
              type="button"
              onClick={() => setShowScanLine((v) => !v)}
              className={`hover:text-cosmos-text transition-colors ${!showScanLine ? 'line-through opacity-50' : ''}`}
            >
              扫描线
            </button>
            <span>|</span>
            <span>双击曲目播放 · 30s 自动切歌</span>
          </div>
        </div>
      </div>

      <div
        className="absolute inset-0 pointer-events-none cosmic-border-glow rounded-lg"
        style={{ zIndex: 20 }}
        aria-hidden
      />
    </div>
  )
}

import { useState, useRef } from 'react'

export default function RightMusicSidebar({
  visible,
  onClose,
  results = [],
  searching,
  onSearch,
  onPlay,
  currentTrack,
  error
}) {
  const [query, setQuery] = useState('')
  const timerRef = useRef(null)

  function handleInput(v) {
    setQuery(v)
    clearTimeout(timerRef.current)
    if (v.trim()) {
      timerRef.current = setTimeout(() => onSearch?.(v), 400)
    }
  }

  if (!visible) return null

  return (
    <aside className="w-64 shrink-0 border-l border-cosmos-border/30 flex flex-col animate-slide-in-right glass-panel">
      <div className="flex items-center justify-between px-4 py-3 border-b border-cosmos-border/30">
        <span className="text-xs font-semibold text-cosmos-dim/80 uppercase tracking-widest font-mono">
          Music Search
        </span>
        <button
          type="button"
          onClick={onClose}
          className="text-cosmos-dim hover:text-red-400 transition-colors text-lg leading-none"
          title="Close"
        >
          ×
        </button>
      </div>

      <div className="px-3 py-3 border-b border-cosmos-border/20">
        <div className="flex items-center gap-2 px-3 py-1.5 rounded-lg border border-cosmos-border/30 bg-cosmos-panel/40">
          <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="rgba(139,139,168,0.6)" strokeWidth="2" strokeLinecap="round">
            <circle cx="11" cy="11" r="8" /><path d="m21 21-4.35-4.35" />
          </svg>
          <input
            type="text"
            value={query}
            onChange={(e) => handleInput(e.target.value)}
            placeholder="搜索 B站 歌曲..."
            spellCheck={false}
            className="flex-1 bg-transparent outline-none text-xs text-cosmos-text/90 font-mono placeholder:text-cosmos-dim/40"
          />
        </div>
      </div>

      <div className="flex-1 overflow-y-auto">
        {error && (
          <div className="px-4 py-3 text-[10px] text-red-400/70 font-mono text-center">
            {error}
          </div>
        )}
        {searching && (
          <div className="px-4 py-8 text-center text-[10px] text-cosmos-dim/50 font-mono">
            Searching...
          </div>
        )}
        {!searching && results.length === 0 && query && (
          <div className="px-4 py-8 text-center text-[10px] text-cosmos-dim/50 font-mono">
            No results
          </div>
        )}
        {!searching && results.length === 0 && !query && (
          <div className="px-4 py-6 text-center text-[10px] text-cosmos-dim/35 font-mono italic">
            搜索 B站音乐 · 双击播放
          </div>
        )}
        {results.map((track, i) => {
          const isActive = currentTrack?.bvid === track.bvid
          return (
            <div
              key={track.bvid || i}
              onDoubleClick={() => onPlay?.(track)}
              className={`group flex items-center gap-3 px-4 py-3 cursor-pointer border-b border-cosmos-border/20
                          transition-colors duration-150 font-mono
                          ${isActive
                            ? 'bg-cosmos-accent/12 text-cosmos-text'
                            : 'text-cosmos-dim/75 hover:bg-cosmos-panel/40 hover:text-cosmos-text/90'
                          }`}
            >
              <span className={`w-5 text-[11px] shrink-0 ${isActive ? 'text-cosmos-accent' : 'text-cosmos-dim/45'}`}>
                {i + 1}
              </span>

              {track.cover && (
                <img src={track.cover} alt="" className="w-8 h-8 rounded object-cover shrink-0" />
              )}

              <div className="flex-1 min-w-0">
                <div className={`text-xs truncate ${isActive ? 'text-cosmos-accent' : 'text-cosmos-text/85'}`}>
                  {track.title}
                </div>
                <div className="text-[10px] text-cosmos-dim/60 truncate mt-0.5">
                  {track.artist}
                </div>
              </div>

              <span className="text-[10px] text-cosmos-dim/45 shrink-0 group-hover:hidden">
                {track.duration || '--:--'}
              </span>

              <button
                type="button"
                onClick={(e) => { e.stopPropagation(); onPlay?.(track) }}
                className="hidden group-hover:flex items-center justify-center w-6 h-6 rounded text-cosmos-accent hover:bg-cosmos-accent/15 transition-colors shrink-0"
                title="Play"
              >
                <svg width="11" height="11" viewBox="0 0 24 24" fill="currentColor">
                  <polygon points="5 3 19 12 5 21 5 3" />
                </svg>
              </button>
            </div>
          )
        })}
      </div>

      <div className="px-4 py-2 border-t border-cosmos-border/20 text-[9px] text-cosmos-dim/45 font-mono text-center">
        Double-click or ▶ to play · 自动连播下一首
      </div>
    </aside>
  )
}

